  39→// MARK: - Argument Parsing
  40→
  41→func parse(arguments: [String]) throws -> ParsedOptions {
  42→    if arguments.isEmpty {
  43→        return ParsedOptions(command: "help", options: [:], flags: [], positionals: [])
  44→    }
  45→
  46→    let command = arguments[0]
  47→    guard supportedCommands.contains(command) else {
  48→        throw NativeError.invalidArguments("Unknown command: \(command)")
  49→    }
  50→
  51→    var options: [String: String] = [:]
  52→    var flags: Set<String> = []
  53→    var positionals: [String] = []
  54→
  55→    var index = 1
  56→    while index < arguments.count {
  57→        let item = arguments[index]
  58→        if item.hasPrefix("--") {
  59→            if let separator = item.firstIndex(of: "=") {
  60→                let key = String(item[..<separator])
  61→                let value = String(item[item.index(after: separator)...])
  62→                options[key] = value
  63→            } else if index + 1 < arguments.count, !arguments[index + 1].hasPrefix("-") {
  64→                options[item] = arguments[index + 1]
  65→                index += 1
  66→            } else {
  67→                flags.insert(item)
  68→            }
  69→        } else if item.hasPrefix("-") {
  70→            if index + 1 < arguments.count, !arguments[index + 1].hasPrefix("-") {
  71→                options[item] = arguments[index + 1]
  72→                index += 1
  73→            } else {
  74→                flags.insert(item)
  75→            }
  76→        } else {
  77→            positionals.append(item)
  78→        }
  79→        index += 1
  80→    }
  81→
  82→    return ParsedOptions(command: command, options: options, flags: flags, positionals: positionals)
  83→}
  84→
  85→// MARK: - Option Helpers
  86→
  87→func requiredOption(_ key: String, from parsed: ParsedOptions) throws -> String {
  88→    if let value = parsed.options[key], !value.isEmpty {
  89→        return value
  90→    }
  91→    throw NativeError.invalidArguments("Missing required option: \(key)")
  92→}
  93→
  94→func optionalDoubleOption(_ key: String, from parsed: ParsedOptions) throws -> Double? {
  95→    guard let raw = parsed.options[key] else {
  96→        return nil
  97→    }
  98→    if let value = Double(raw) {
  99→        return value
 100→    }
 101→    throw NativeError.invalidArguments("Invalid numeric value for \(key): \(raw)")
 102→}
