 104→func parseCommaSeparatedInts(_ raw: String, label: String) throws -> [Int] {
 105→    let parts = raw.split(separator: ",")
 106→    if parts.isEmpty {
 107→        throw NativeError.invalidArguments("Missing \(label) values")
 108→    }
 109→    var result: [Int] = []
 110→    for part in parts {
 111→        if let value = Int(part.trimmingCharacters(in: .whitespacesAndNewlines)) {
 112→            result.append(value)
 113→        } else {
 114→            throw NativeError.invalidArguments("Invalid \(label) value: \(part)")
 115→        }
 116→    }
 117→    return result
 118→}
