 132→// MARK: - Process Execution
 133→
 134→@discardableResult
 135→func runProcess(_ command: String, _ arguments: [String]) throws -> Int32 {
 136→    let process = Process()
 137→    process.executableURL = URL(fileURLWithPath: command)
 138→    process.arguments = arguments
 139→    process.standardInput = FileHandle.standardInput
 140→    process.standardOutput = FileHandle.standardOutput
 141→    process.standardError = FileHandle.standardError
 142→
 143→    do {
 144→        try process.run()
 145→    } catch {
 146→        throw NativeError.commandFailed("Failed to launch process: \(command) \(arguments.joined(separator: " "))")
 147→    }
 148→
 149→    process.waitUntilExit()
 150→    return process.terminationStatus
 151→}
 152→
 153→@discardableResult
 154→func runProcessWithTimeout(_ command: String, _ arguments: [String], timeoutSeconds: Double) throws -> Int32 {
 155→    let process = Process()
 156→    process.executableURL = URL(fileURLWithPath: command)
 157→    process.arguments = arguments
 158→    process.standardInput = FileHandle.standardInput
 159→    process.standardOutput = FileHandle.standardOutput
 160→    process.standardError = FileHandle.standardError
 161→
 162→    do {
 163→        try process.run()
 164→    } catch {
 165→        throw NativeError.commandFailed("Failed to launch process: \(command) \(arguments.joined(separator: " "))")
 166→    }
 167→
 168→    let group = DispatchGroup()
 169→    group.enter()
 170→    process.terminationHandler = { _ in
 171→        group.leave()
 172→    }
 173→
 174→    if group.wait(timeout: .now() + timeoutSeconds) == .timedOut {
 175→        process.interrupt()
 176→        if group.wait(timeout: .now() + 1.0) == .timedOut {
 177→            process.terminate()
 178→            group.wait()
 179→        }
 180→    }
 181→
 182→    return process.terminationStatus
 183→}
