 185→// MARK: - Target Resolution
 186→
 187→func resolveTarget(from parsed: ParsedOptions) throws -> TargetApp {
 188→    let hasUdid = parsed.options["--udid"] != nil
 189→    let hasBundleId = parsed.options["--bundle-id"] != nil
 190→    let hasAppName = parsed.options["--app-name"] != nil
 191→
 192→    let macTargetCount = (hasBundleId ? 1 : 0) + (hasAppName ? 1 : 0)
 193→    if hasUdid && macTargetCount > 0 {
 194→        throw NativeError.invalidArguments("Cannot use --udid with --bundle-id or --app-name. Choose simulator or macOS app target.")
 195→    }
 196→    if macTargetCount > 1 {
 197→        throw NativeError.invalidArguments("Cannot use both --bundle-id and --app-name. Choose one.")
 198→    }
 199→
 200→    if hasUdid {
 201→        return .simulator(udid: parsed.options["--udid"]!)
 202→    }
 203→
 204→    if let bundleId = parsed.options["--bundle-id"] {
 205→        let apps = NSRunningApplication.runningApplications(withBundleIdentifier: bundleId)
 206→        guard let app = apps.first else {
 207→            throw NativeError.commandFailed("No running application found with bundle ID: \(bundleId)")
 208→        }
 209→        return .macApp(pid: app.processIdentifier, bundleId: bundleId, name: app.localizedName)
 210→    }
 211→
 212→    if let appName = parsed.options["--app-name"] {
 213→        let apps = NSWorkspace.shared.runningApplications.filter {
 214→            $0.activationPolicy == .regular && $0.localizedName == appName
 215→        }
 216→        guard let app = apps.first else {
 217→            throw NativeError.commandFailed("No running application found with name: \(appName)")
 218→        }
 219→        return .macApp(pid: app.processIdentifier, bundleId: app.bundleIdentifier, name: appName)
 220→    }
 221→
 222→    throw NativeError.invalidArguments("Target required: use --udid for simulator, or --bundle-id / --app-name for macOS app.")
 223→}
