 240→func ensureAccessibilityTrusted() throws {
 241→    if AXIsProcessTrusted() {
 242→        return
 243→    }
 244→
 245→    throw NativeError.commandFailed(
 246→        """
 247→        [Permission Denied] Accessibility access is required to read/control Simulator UI (including apps running inside it) and send input events.
 248→
 249→        Most commonly this happens because either the MCP client app or the terminal app running mcp-baepsae does not have Accessibility permission.
 250→
 251→        Please enable it in macOS System Settings:
 252→        1. Open 'System Settings' -> 'Privacy & Security' -> 'Accessibility'.
 253→        2. Find both the MCP client app and terminal app you used, and also the Node.js runtime ('node') in the list.
 254→        3. Turn the switch ON.
 255→        4. If it's already ON, try turning it OFF and ON again, or restart your terminal.
 256→        """
 257→    )
 258→}
