 288→func copyMultipleAttributes(_ element: UIElement, _ attributes: [String]) -> [String: CFTypeRef] {
 289→    var result = [String: CFTypeRef]()
 290→    var values: CFArray?
 291→    let cfAttributes = attributes as CFArray
 292→    let status = AXUIElementCopyMultipleAttributeValues(element, cfAttributes, AXCopyMultipleAttributeOptions(rawValue: 0), &values)
 293→    guard status == .success, let array = values as? [Any?] else {
 294→        return result
 295→    }
 296→    for (index, attribute) in attributes.enumerated() {
 297→        guard index < array.count, let value = array[index] else { continue }
 298→        let typeRef = value as CFTypeRef
 299→        if CFGetTypeID(typeRef) != 0 {
 300→            result[attribute] = typeRef
 301→        }
 302→    }
 303→    return result
 304→}
