 306→func stringFromCFTypeRef(_ value: CFTypeRef) -> String? {
 307→    if let stringValue = value as? String {
 308→        return stringValue
 309→    }
 310→    if let attributed = value as? NSAttributedString {
 311→        return attributed.string
 312→    }
 313→    if let numberValue = value as? NSNumber {
 314→        return numberValue.stringValue
 315→    }
 316→    return nil
 317→}
