 319→func frameFromCFTypeRef(_ value: CFTypeRef) -> CGRect? {
 320→    guard let axValue = ValueFromCFType(value), AXValueGetType(axValue) == .cgRect else {
 321→        return nil
 322→    }
 323→    var rect = CGRect.zero
 324→    guard AXValueGetValue(axValue, .cgRect, &rect) else {
 325→        return nil
 326→    }
 327→    return rect
 328→}
