 419→func truncateText(_ value: String, maxLength: Int = 80) -> String {
 420→    let singleLine = value.replacingOccurrences(of: "\n", with: " ").trimmingCharacters(in: .whitespacesAndNewlines)
 421→    if singleLine.count <= maxLength {
 422→        return singleLine
 423→    }
 424→    return String(singleLine.prefix(maxLength - 3)) + "..."
 425→}
