 433→let describeAttributes: [String] = [
 434→    kAXRoleAttribute as String,
 435→    kAXSubroleAttribute as String,
 436→    "AXIdentifier",
 437→    "AXLabel",
 438→    kAXTitleAttribute as String,
 439→    kAXDescriptionAttribute as String,
 440→    kAXValueAttribute as String,
