 448→func describeAccessibilityElement(_ element: UIElement, includeEmpty: Bool = true) -> String? {
 449→    let attrs = copyMultipleAttributes(element, describeAttributes)
 450→    var parts: [String] = []
 451→
 452→    let role: String
 453→    if let roleRef = attrs[kAXRoleAttribute as String], let s = stringFromCFTypeRef(roleRef), !s.isEmpty {
 454→        role = s
 455→    } else {
 456→        role = "unknown"
 457→    }
 458→    parts.append("role=\(role)")
 459→
 460→    if let ref = attrs[kAXSubroleAttribute as String], let s = stringFromCFTypeRef(ref), !s.isEmpty {
 461→        parts.append("subrole=\(s)")
 462→    }
 463→
 464→    if let ref = attrs["AXIdentifier"], let s = stringFromCFTypeRef(ref), !s.isEmpty {
 465→        parts.append("id=\(truncateText(s))")
 466→    }
 467→
 468→    var textSources: [String] = []
 469→    let textKeys: [(String, String?)] = [
 470→        ("AXLabel", nil),
 471→        (kAXTitleAttribute as String, nil),
 472→        (kAXDescriptionAttribute as String, nil),
 473→        (kAXValueAttribute as String, nil),
 474→        (kAXHelpAttribute as String, nil),
 475→        ("AXPlaceholderValue", "placeholder:"),
 476→    ]
 477→    for (key, prefix) in textKeys {
 478→        if let ref = attrs[key], let s = stringFromCFTypeRef(ref), !s.isEmpty {
 479→            textSources.append(prefix != nil ? "\(prefix!)\(s)" : s)
 480→        }
 481→    }
 482→
 483→    let uniqueTexts = Array(Set(textSources)).filter { !$0.isEmpty }
 484→
 485→    if !uniqueTexts.isEmpty {
 486→        let combinedText = uniqueTexts.joined(separator: " | ")
 487→        parts.append("text=\(truncateText(combinedText))")
 488→    }
 489→
 490→    if let ref = attrs[kAXEnabledAttribute as String], let s = stringFromCFTypeRef(ref) {
 491→        if s.lowercased() == "false" || s == "0" {
 492→            parts.append("enabled=false")
 493→        }
 494→    }
 495→
 496→    if let ref = attrs["AXSelected"], let s = stringFromCFTypeRef(ref) {
 497→        if s.lowercased() == "true" || s == "1" {
 498→            parts.append("selected=true")
 499→        }
 500→    }
 501→
 502→    if let ref = attrs["AXFrame"], let frame = frameFromCFTypeRef(ref) {
 503→        let frameText = "frame=(x:\(formatFloat(frame.origin.x)),y:\(formatFloat(frame.origin.y)),w:\(formatFloat(frame.size.width)),h:\(formatFloat(frame.size.height)))"
 504→        parts.append(frameText)
 505→    }
 506→
 507→    if !includeEmpty && uniqueTexts.isEmpty {
 508→        if attrs["AXIdentifier"] == nil || (stringFromCFTypeRef(attrs["AXIdentifier"]!) ?? "").isEmpty {
 509→            let children = Children(element)
 510→            if children.isEmpty {
 511→                return nil
 512→            }
 513→        }
 514→    }
 515→
 516→    return parts.joined(separator: " ")
 517→}
