 519→func describeAccessibilityTree(from root: UIElement, options: DescribeOptions = DescribeOptions()) -> [String] {
 520→    var lines: [String] = []
 521→    var stack: [(element: UIElement, depth: Int)] = [(root, 0)]
 522→    var totalNodes = 0
 523→    var emitted = 0
 524→
 525→    while let current = stack.popLast() {
 526→        let element = current.element
 527→        let depth = current.depth
 528→
 529→        // Apply filters
 530→        if options.roleFilter != nil || options.visibleOnly {
 531→            let attrs = copyMultipleAttributes(element, [kAXRoleAttribute as String, "AXFrame"])
 532→            if let roleFilter = options.roleFilter {
 533→                if let roleRef = attrs[kAXRoleAttribute as String], let role = stringFromCFTypeRef(roleRef) {
 534→                    if role != roleFilter {
 535→                        // Still traverse children even if this node doesn't match
 536→                        if depth < options.maxDepth {
 537→                            let children = Children(element)
 538→                            for child in children.reversed() {
 539→                                stack.append((child, depth + 1))
 540→                            }
 541→                        }
 542→                        continue
 543→                    }
 544→                } else {
 545→                    if depth < options.maxDepth {
 546→                        let children = Children(element)
 547→                        for child in children.reversed() {
 548→                            stack.append((child, depth + 1))
 549→                        }
 550→                    }
 551→                    continue
 552→                }
 553→            }
 554→            if options.visibleOnly, let screenBounds = options.screenBounds {
 555→                if let frameRef = attrs["AXFrame"], let frame = frameFromCFTypeRef(frameRef) {
 556→                    if !screenBounds.intersects(frame) {
 557→                        if depth < options.maxDepth {
 558→                            let children = Children(element)
 559→                            for child in children.reversed() {
 560→                                stack.append((child, depth + 1))
 561→                            }
 562→                        }
 563→                        continue
 564→                    }
 565→                }
 566→            }
 567→        }
 568→
 569→        totalNodes += 1
 570→        let prefix = String(repeating: "  ", count: depth)
 571→
 572→        // Pagination: only emit nodes within [offset, offset+limit)
 573→        if totalNodes > options.offset && emitted < options.limit {
 574→            if options.summary {
 575→                let children = Children(element)
 576→                if let description = describeAccessibilityElement(element) {
 577→                    if !children.isEmpty {
 578→                        lines.append("\(prefix)- \(description) [\(children.count) children]")
 579→                    } else {
 580→                        lines.append("\(prefix)- \(description)")
 581→                    }
 582→                }
 583→                emitted += 1
 584→                // In summary mode, don't recurse into children
 585→                continue
 586→            } else {
 587→                if let description = describeAccessibilityElement(element) {
 588→                    lines.append("\(prefix)- \(description)")
 589→                } else {
 590→                    lines.append("\(prefix)- [hidden: no accessible content]")
 591→                }
 592→                emitted += 1
 593→            }
 594→        }
 595→
 596→        if depth >= options.maxDepth {
 597→            continue
 598→        }
 599→
 600→        let children = Children(element)
 601→        for child in children.reversed() {
 602→            stack.append((child, depth + 1))
 603→        }
 604→    }
 605→
 606→    // Add pagination header/footer
 607→    if options.offset > 0 || options.limit < Int.max {
 608→        let start = options.offset + 1
 609→        let end = options.offset + emitted
 610→        lines.insert("[Total: \(totalNodes) nodes]", at: 0)
 611→        lines.append("[Showing \(start)-\(end) of \(totalNodes)]")
 612→    }
 613→
 614→    return lines
 615→}
