 645→func matchesAccessibilityElement(_ element: UIElement, identifier: String?, label: String?) -> Bool {
 646→    guard identifier != nil || label != nil else { return false }
 647→
 648→    let attrs = copyMultipleAttributes(element, matchAttributes)
 649→
 650→    if let identifier {
 651→        guard let ref = attrs["AXIdentifier"], let s = stringFromCFTypeRef(ref),
 652→              normalizeText(s) == normalizeText(identifier) else {
 653→            return false
 654→        }
 655→    }
 656→
 657→    if let label {
 658→        let textKeys = ["AXLabel", kAXTitleAttribute as String, kAXDescriptionAttribute as String, kAXValueAttribute as String, kAXHelpAttribute as String]
 659→        let matches = textKeys.contains { key in
 660→            guard let ref = attrs[key], let s = stringFromCFTypeRef(ref), !s.isEmpty else { return false }
 661→            return normalizeText(s) == normalizeText(label)
 662→        }
 663→        if !matches {
 664→            return false
 665→        }
 666→    }
 667→
 668→    return true
 669→}
