 671→func findAccessibilityElement(
 672→    in root: UIElement,
 673→    identifier: String?,
 674→    label: String?,
 675→    maxDepth: Int = Int.max,
 676→    maxNodes: Int = Int.max
 677→) -> UIElement? {
 678→    var stack: [(element: UIElement, depth: Int)] = [(root, 0)]
 679→    var visited = 0
 680→
 681→    while let current = stack.popLast() {
 682→        if visited >= maxNodes {
 683→            break
 684→        }
 685→
 686→        visited += 1
 687→        if matchesAccessibilityElement(current.element, identifier: identifier, label: label) {
 688→            return current.element
 689→        }
 690→
 691→        if current.depth >= maxDepth {
 692→            continue
 693→        }
 694→
 695→        let children = Children(current.element)
 696→        for child in children.reversed() {
 697→            stack.append((child, current.depth + 1))
 698→        }
 699→    }
 700→
 701→    return nil
 702→}
