 704→func searchAccessibilityElements(in root: UIElement, query: String, options: SearchOptions = SearchOptions()) -> [String] {
 705→    var results: [String] = []
 706→    var stack: [(element: UIElement, depth: Int)] = [(root, 0)]
 707→    let normalizedQuery = normalizeText(query)
 708→
 709→    let searchAttributes: [String] = [
 710→        "AXIdentifier",
 711→        "AXLabel",
 712→        kAXTitleAttribute as String,
 713→        kAXDescriptionAttribute as String,
 714→        kAXValueAttribute as String,
 715→        kAXHelpAttribute as String,
 716→    ]
 717→
 718→    while let current = stack.popLast() {
 719→        let element = current.element
 720→        let depth = current.depth
 721→
 722→        // Fetch search attributes + filter attributes in one call
 723→        var allAttrs = searchAttributes
 724→        if options.roleFilter != nil { allAttrs.append(kAXRoleAttribute as String) }
 725→        if options.visibleOnly { allAttrs.append("AXFrame") }
 726→        let attrs = copyMultipleAttributes(element, allAttrs)
 727→
 728→        // Apply role filter
 729→        if let roleFilter = options.roleFilter {
 730→            if let roleRef = attrs[kAXRoleAttribute as String], let role = stringFromCFTypeRef(roleRef) {
 731→                if role != roleFilter {
 732→                    if depth < options.maxDepth {
 733→                        let children = Children(element)
 734→                        for child in children.reversed() {
 735→                            stack.append((child, depth + 1))
 736→                        }
 737→                    }
 738→                    continue
 739→                }
 740→            } else {
 741→                if depth < options.maxDepth {
 742→                    let children = Children(element)
 743→                    for child in children.reversed() {
 744→                        stack.append((child, depth + 1))
 745→                    }
 746→                }
 747→                continue
 748→            }
 749→        }
 750→
 751→        // Apply visible-only filter
 752→        if options.visibleOnly, let screenBounds = options.screenBounds {
 753→            if let frameRef = attrs["AXFrame"], let frame = frameFromCFTypeRef(frameRef) {
 754→                if !screenBounds.intersects(frame) {
 755→                    if depth < options.maxDepth {
 756→                        let children = Children(element)
 757→                        for child in children.reversed() {
 758→                            stack.append((child, depth + 1))
 759→                        }
 760→                    }
 761→                    continue
 762→                }
 763→            }
 764→        }
 765→
 766→        // Check text match
 767→        var matchFound = false
 768→        for key in searchAttributes {
 769→            if let ref = attrs[key], let s = stringFromCFTypeRef(ref), !s.isEmpty,
 770→               normalizeText(s).contains(normalizedQuery) {
 771→                matchFound = true
 772→                break
 773→            }
 774→        }
 775→
 776→        if matchFound {
 777→            if let desc = describeAccessibilityElement(element) {
 778→                results.append(desc)
 779→            }
 780→        }
 781→
 782→        if depth < options.maxDepth {
 783→            let children = Children(element)
 784→            for child in children.reversed() {
 785→                stack.append((child, depth + 1))
 786→            }
 787→        }
 788→    }
 789→    return results
 790→}
