 792→func findElementBySubrole(from root: UIElement, subrole: String) -> UIElement? {
 793→    var stack: [UIElement] = [root]
 794→    var visited = 0
 795→    while let current = stack.popLast() {
 796→        if visited > 500 { break }
 797→        visited += 1
 798→
 799→        let attrs = copyMultipleAttributes(current, [kAXSubroleAttribute as String])
 800→        if let ref = attrs[kAXSubroleAttribute as String], let sr = stringFromCFTypeRef(ref), sr == subrole {
 801→            return current
 802→        }
 803→
 804→        for child in Children(current).reversed() {
 805→            stack.append(child)
 806→        }
 807→    }
 808→    return nil
