 921→func activateSimulator(udid: String?) throws {
 922→    let bundleIdentifier = "com.apple.iphonesimulator"
 923→
 924→    // When UDID is provided, always pass it to Simulator so the intended device
 925→    // becomes current even if Simulator is already running.
 926→    if let udid, !udid.isEmpty {
 927→        _ = try runProcess("/usr/bin/open", ["-a", "Simulator", "--args", "-CurrentDeviceUDID", udid])
 928→        Thread.sleep(forTimeInterval: 0.4)
 929→    } else {
 930→        let running = NSRunningApplication.runningApplications(withBundleIdentifier: bundleIdentifier)
 931→        if running.isEmpty {
 932→            _ = try runProcess("/usr/bin/open", ["-a", "Simulator"])
 933→            Thread.sleep(forTimeInterval: 0.4)
 934→        }
 935→    }
 936→
 937→    let runningNow = NSRunningApplication.runningApplications(withBundleIdentifier: bundleIdentifier)
 938→    for app in runningNow {
 939→        app.activate(options: [.activateAllWindows])
 940→    }
