 970→func sendDoubleClick(at point: CGPoint) {
 971→    let source = CGEventSource(stateID: .hidSystemState)
 972→    // First click
 973→    let down1 = CGEvent(mouseEventSource: source, mouseType: .leftMouseDown, mouseCursorPosition: point, mouseButton: .left)
 974→    down1?.setIntegerValueField(.mouseEventClickState, value: 1)
 975→    down1?.post(tap: .cghidEventTap)
 976→    let up1 = CGEvent(mouseEventSource: source, mouseType: .leftMouseUp, mouseCursorPosition: point, mouseButton: .left)
 977→    up1?.setIntegerValueField(.mouseEventClickState, value: 1)
 978→    up1?.post(tap: .cghidEventTap)
 979→    // Second click
 980→    let down2 = CGEvent(mouseEventSource: source, mouseType: .leftMouseDown, mouseCursorPosition: point, mouseButton: .left)
 981→    down2?.setIntegerValueField(.mouseEventClickState, value: 2)
 982→    down2?.post(tap: .cghidEventTap)
 983→    let up2 = CGEvent(mouseEventSource: source, mouseType: .leftMouseUp, mouseCursorPosition: point, mouseButton: .left)
 984→    up2?.setIntegerValueField(.mouseEventClickState, value: 2)
 985→    up2?.post(tap: .cghidEventTap)
