 988→func sendSwipe(from start: CGPoint, to end: CGPoint, duration: Double?) {
 989→    postMouseEvent(type: .leftMouseDown, point: start)
 990→    let steps = 10
 991→    for step in 1...steps {
 992→        let progress = CGFloat(step) / CGFloat(steps)
 993→        let x = start.x + (end.x - start.x) * progress
 994→        let y = start.y + (end.y - start.y) * progress
 995→        postMouseEvent(type: .leftMouseDragged, point: CGPoint(x: x, y: y))
 996→        if let duration {
 997→            Thread.sleep(forTimeInterval: duration / Double(steps))
 998→        }
 999→    }
1000→    postMouseEvent(type: .leftMouseUp, point: end)
1001→}
