1008→    let keyUp = CGEvent(keyboardEventSource: source, virtualKey: CGKeyCode(keyCode), keyDown: false)
1009→    keyDown?.post(tap: .cghidEventTap)
1010→    if let duration {
1011→        Thread.sleep(forTimeInterval: duration)
1012→    }
