1022→    let keyDown = CGEvent(keyboardEventSource: source, virtualKey: CGKeyCode(key), keyDown: true)
1023→    let keyUp = CGEvent(keyboardEventSource: source, virtualKey: CGKeyCode(key), keyDown: false)
1024→    keyDown?.post(tap: .cghidEventTap)
1025→    keyUp?.post(tap: .cghidEventTap)
1026→    for modifier in modifiers.reversed() {
1027→        let event = CGEvent(keyboardEventSource: source, virtualKey: CGKeyCode(modifier), keyDown: false)
