1038→        }
1039→        var char = UniChar(value)
1040→        let keyDown = CGEvent(keyboardEventSource: source, virtualKey: 0, keyDown: true)
1041→        keyDown?.keyboardSetUnicodeString(stringLength: 1, unicodeString: &char)
1042→        keyDown?.post(tap: .cghidEventTap)
1043→        let keyUp = CGEvent(keyboardEventSource: source, virtualKey: 0, keyDown: false)
1044→        keyUp?.keyboardSetUnicodeString(stringLength: 1, unicodeString: &char)
