        y: 200,
      },
    });
    const text = extractText(result);
    assert.match(text, /baepsae-native/);
    assert.match(text, /-x/);
    assert.match(text, /-y/);
  });
});

test("tap with --double flag is forwarded", async () => {
  await withClient(async (client) => {
    const result = await client.callTool({
      name: "tap",
