  pushOption(args, "--delta-x", params.deltaX);
  pushOption(args, "--delta-y", params.deltaY);
  pushOption(args, "-x", params.x);
  pushOption(args, "-y", params.y);
  return args;
}

function buildDragDropArgs(target: string[], params: DragDropParams): string[] {
