test("tool registry lists all 32 expected MCP tools", async () => {
  await withClient(async (client) => {
    const result = await client.listTools();
    const names = new Set(result.tools.map((t) => t.name));

    const allExpected = [
      "baepsae_help",
      "baepsae_version",
      "list_simulators",
      "list_apps",
      "open_url",
      "install_app",
      "launch_app",
      "terminate_app",
      "uninstall_app",
      "button",
      "gesture",
      "stream_video",
      "record_video",
      "screenshot",
      "menu_action",
      "get_focused_app",
      "clipboard",
      "analyze_ui",
      "query_ui",
      "tap",
      "type_text",
      "swipe",
      "scroll",
      "drag_drop",
      "key",
      "key_sequence",
      "key_combo",
      "touch",
      "list_windows",
      "activate_app",
      "screenshot_app",
      "right_click",
    ];

    for (const name of allExpected) {
      assert.ok(names.has(name), `Missing tool: ${name}`);
    }

    assert.equal(names.size, allExpected.length, `Expected ${allExpected.length} tools, got ${names.size}`);
  });
});

