 6→/// Normalizes pixel coordinates to 0-1 ratio for IndigoHID.
 7→/// IndigoHID expects coordinates as fractions of the screen dimensions.
 8→struct IndigoHIDCoordinates {
 9→    let screenWidth: Double
10→    let screenHeight: Double
11→
12→    init(screenWidth: Double, screenHeight: Double) {
13→        self.screenWidth = max(1, screenWidth)
14→        self.screenHeight = max(1, screenHeight)
15→    }
16→
17→    /// Convert point coordinates (pixels) to normalized 0-1 ratio.
18→    /// Origin is top-left.
19→    func normalize(x: Double, y: Double) -> (x: Double, y: Double) {
20→        return (x / screenWidth, y / screenHeight)
21→    }
22→
23→    /// Create a touch point from pixel coordinates.
24→    func touchPoint(x: Double, y: Double, phase: IndigoHIDTouchPhase, finger: UInt32 = 1) -> IndigoHIDTouchPoint {
25→        let (nx, ny) = normalize(x: x, y: y)
26→        return IndigoHIDTouchPoint(x: nx, y: ny, phase: phase, finger: finger)
27→    }
28→}
